async function seed() {
    try {
        await mongoose.connect(process.env.MONGO_URI);
        console.log('Connected to MongoDB');

        // Clear existing courses
        await Course.deleteMany({});
        console.log('Cleared existing courses');

        const finalCourses = [];
        const detailedMap = new Map(detailedCourses.map(c => [c.id, c]));

        for (const base of baseCourses) {
            if (detailedMap.has(base.id)) {
                finalCourses.push(detailedMap.get(base.id));
            } else {
                // Fallback mapping
                const priceNum = parseInt(base.price.replace(/[^\d]/g, "")) || 25000;
                finalCourses.push({
                    id: base.id,
                    collegeId: base.providerType === "redapple" ? "redapple" : "generic",
                    title: base.title,
                    domain: base.domain,
                    description: `${base.title} — a comprehensive program by ${base.provider} covering ${base.skills.slice(0, 4).join(", ")} and more.`,
                    duration: base.duration,
                    mode: base.mode === "offline" ? "offline" : (base.mode === "hybrid" ? "hybrid" : "online"),
                    schedule: "flexible",
                    marketPrice: Math.round(priceNum * 1.5),
                    coursePrice: priceNum,
                    emiOptions: "EMI available",
                    scholarships: "Merit-based scholarships available",
                    limitedOffer: "Limited seats — enroll now",
                    modules: [
                        { name: "Core Curriculum", topics: base.skills.slice(0, 4) },
                        { name: "Advanced Topics", topics: base.skills.slice(4, 8) }
                    ],
                    tools: base.skills.slice(0, 6),
                    projects: ["Industry Project", "Portfolio Piece"],
                    skillsCovered: base.skills,
                    careerRoles: base.careers,
                    careerOutcomes: base.careers.slice(0, 3).map(role => ({ role, salaryRange: "₹4–15 LPA", growthTrajectory: "Growth in 2-3 years" })),
                    testimonials: [{ name: "Student", feedback: "Great learning experience.", rating: 5, image: "" }],
                    nextBatchDate: "April 2026",
                    seatsLeft: 20,
                    expectedSalary: "₹4–15 LPA"
                });
            }
        }

        const result = await Course.insertMany(finalCourses);
        console.log(`Successfully seeded ${result.length} courses`);
        process.exit(0);
    } catch (error) {
        console.error('Seeding failed:', error);
        process.exit(1);
    }
}

seed();
